export type SvgIcon = (props: SVGProps<SVGSVGElement>) => React.ReactElement;

export const SKILL_ICONS: Record<string, SvgIcon> = {
  javascript: JavascriptIcon,
  typescript: TypescriptIcon,
  java: JavaIcon,
  react: ReactIcon,
  reactnative: ReactIcon,
  nextjs: NextIcon,
  next: NextIcon,
  zustand: ZustandIcon,
  redux: ReduxIcon,
  tanstackquery: TanstackQueryIcon,
  recoil: RecoilIcon,
  tailwind: TailwindIcon,
  tailwindcss: TailwindIcon,
  sass: SassIcon,
  styledcomponents: StyledComponentsIcon,
  jest: JestIcon,
  storybook: StorybookIcon,
  vite: ViteIcon,
  docker: DockerIcon,
  github: GithubIcon,
  gitlab: GitlabIcon,
  jira: JiraIcon,
  figma: FigmaIcon,
  notion: NotionIcon,
  linux: LinuxIcon,
  oracle: OracleIcon,
  solidity: SolidityIcon,
  electron: ElectronIcon,
  springboot: SpringbootIcon,
  nginx: NginxIcon,
  postgresql: PostgresqlIcon,
};

export const getSkillIcon = (name: string): SvgIcon | undefined =>
  SKILL_ICONS[name.toLowerCase().replace(/[\s\-_]/g, '')];
